fn solve(code: Vec<String>, businessLine: Vec<String>, isActive: Vec<bool>) -> Vec<String> {
    let valid_business_lines = ["electronics", "grocery", "pharmacy", "restaurant"];
    let mut valid_coupons = Vec::new();

    for i in 0..code.len() {
        if !isActive[i] {
            continue;
        }

        let code_str = &code[i];
        let business_str = &businessLine[i];

        // Check if code is non-empty and only contains allowed characters
        if code_str.is_empty() {
            continue;
        }

        if !code_str.chars().all(|c| c.is_alphanumeric() || c == '_') {
            continue;
        }

        // Check if business line is valid
        if !valid_business_lines.contains(&business_str) {
            continue;
        }

        valid_coupons.push((business_str.clone(), code_str.clone()));
    }

    // Sort by business line order and then by code dictionary order
    valid_coupons.sort_by(|a, b| {
        let a_index = valid_business_lines.iter().position(|x| x == a.0).unwrap();
        let b_index = valid_business_lines.iter().position(|x| x == b.0).unwrap();
        if a_index != b_index {
            a_index.cmp(&b_index)
        } else {
            a.1.cmp(b.1)
        }
    });

    // Extract the codes in the sorted order
    valid_coupons.into_iter().map(|(_, code)| code).collect()
}
